+    #[test]
+    fn fingerprint_mismatch_detected() {
+        let dir = tempdir().unwrap();
+        let config = test_config(dir.path());
+
+        // Create index
+        let _indexer = LexicalIndexer::open(config.clone()).unwrap();
+        drop(_indexer);
